import requests
import time

def main(event):
  # this script is updating the opensolar project with the hubspot deal ID
  os_id = event["inputFields"]["os_id"]
  deal_id = event["inputFields"]["deal_id"]

  # returning if no os_id or deal_id
  if not os_id or not deal_id:
    return

  # build the opensolar api url
  update_url = "https://api.opensolar.com/api/orgs/8609/projects/" + os_id + "/"

  # building body for update
  body = {"custom_project_info_2": deal_id}

  # headers with auth
  headers = {
    "Authorization": "Bearer s_ASYN6D7IZHDYWMMWIMYFAGXKXATZQYZQ",
    "Content-Type": "application/json"
  }

  # retry up to 3 times
  max_retries = 3
  for attempt in range(max_retries):
    try:
      response = requests.patch(update_url, json=body, headers=headers)
      response.raise_for_status()
      return response.json()
    except requests.exceptions.RequestException as e:
      if attempt < max_retries - 1:
        time.sleep(2 ** attempt)
        continue
      else:
        raise e

